queryRules.ruleDef:
#define "maxCount" as int default "50" hint "表最大字段数量"
if @domain.sqlType != 'CREATE_TABLE' then return true end
return @func.array.size(@domain.columns) <= cast(#{maxCount} as int)

if
  @domain.sqlType == 'CREATE_TABLE'
then
  return @func.string.isNotBlank(@domain.comment)
end

if
  @domain.sqlType == 'ALTER_TABLE' and
  @domain.comment != null
then
  return @func.string.isNotBlank(@domain.comment)
end

#define "length" as int default "30" hint "表名的最大长度"
if @domain.sqlType in ['CREATE_TABLE', 'CREATE_TABLE_SELECT', 'CREATE_TABLE_LIKE'] then checkName = @domain.table elseif @domain.sqlType in ['RENAME_TABLE', 'ALTER_TABLE_RENAME'] then checkName = @domain.newName else return true end
return @func.string.length(checkName) <= cast(#{length} as int)

if
  @domain.sqlType not in ['CREATE_TABLE_ADD_COLUMN', 'ALTER_TABLE_ADD_COLUMN', 'ALTER_TABLE_ALTER_COLUMN']
then
  return true
end

return !cast(@domain.zerofill as bool)

if
  @domain.sqlType in ['CREATE_TABLE_ADD_COLUMN', 'ALTER_TABLE_ADD_COLUMN']
then
  return @func.string.isNotBlank(@domain.comment)
end

if
  @domain.sqlType == 'ALTER_TABLE_ALTER_COLUMN' and
  @domain.comment != null
then
  return @func.string.isNotBlank(@domain.comment)
end

if
  @domain.sqlType in ['CREATE_TABLE_ADD_COLUMN', 'ALERT_TABLE_ADD_COLUMN']
then
  return @domain.defaultValue != null
end

if
  @domain.sqlType == 'ALERT_TABLE_ALERT_COLUMN' and
  @domain.defaultValue != null
then
  return @func.string.isNotBlank(@domain.defaultValue)
end

#define "length" as int default "30" hint "列名的最大长度"
if @domain.sqlType in ['CREATE_TABLE_ADD_COLUMN', 'ALTER_TABLE_ADD_COLUMN'] then checkName = @domain.column elseif @domain.sqlType == 'ALTER_TABLE_RENAME_COLUMN' then checkName = @domain.newName else return true end
return @func.string.length(checkName) <= cast(#{length} as int)

if
  @domain.sqlType == 'ALTER_TABLE_ALTER_COLUMN' and
  @domain.defaultValue != null
then
  return @func.string.isNotBlank(@domain.defaultValue)
end

if
  @domain.sqlType in ['UPDATE']
then
  return cast(@domain.hasLimit as bool)
end

if
  @domain.sqlType in ['INSERT']
then
  return cast(@domain.hasSpecifyColumn as bool)
end

if
  @domain.sqlType in ['DELETE']
then
  return cast(@domain.hasLimit as bool)
end
